compositionExample.code:
final class Branch extends Model implements BranchInterface
{
    use HasFactory;
    use HasUlids;

    use BelongsToTenant;         // Tenancy — adds tenant_id + global scope

    use HasSystemFlag;           // Foundation — is_system flag
    use HasUserstamps;           // Foundation — created_by / updated_by / deleted_by
    use HasAuditable;            // Foundation — audit trail
    use SoftDeletes;             // Framework

    use BelongsToOrganization;   // Organization
    use BelongsToRegion;         // Region
}

blueprintExample.code:
Schema::create('branches', function (Blueprint $t) {
    $t->string('id', 64)->primary();  // brn_<ulid>
    $t->tenantable();                  // Tenancy — tenant_id + FK + (tenant_id, created_at) index
    $t->organizable();                 // Organization — organization_id + FK
    $t->regionable();                  // Region — region_id + FK
    $t->string('name');
    $t->string('slug');
    $t->boolean('is_system')->default(false);
    $t->userstampable();               // Foundation — created_by / updated_by / deleted_by
    $t->softDeletes();
    $t->timestamps();
});

// Boundary rows use ->applicable() instead of ->tenantable():
Schema::create('tenants', function (Blueprint $t) {
    $t->string('id', 64)->primary();  // ten_<ulid>
    $t->applicable();                  // Tenancy — application_id + FK
    $t->string('slug', 63);
    $t->string('name', 200);
    // ...
});
